    /// </summary>
    private static bool IsGameplayBlockingUserInterface(GameObject target)
    {
        if (target == null)
        {
            return false;
        }

        if (target.GetComponentInParent<TowerShopCard>() != null)
        {
            return true;
        }

        return target.GetComponentInParent<Selectable>() != null;
    }

